<?php namespace App\Services\System; use Exception; class EnvironmentChecker { protected array $requiredExtensions = ['bcmath', 'ctype', 'curl', 'dom', 'fileinfo', 'filter', 'hash', 'mbstring', 'openssl', 'pcre', 'pdo', 'session', 'tokenizer', 'xml', 'gd', 'zip']; protected array $requiredDirectories = ['storage', 'bootstrap/cache']; public function check(): array { $report = ['status' => true, 'errors' => []]; foreach ($this->requiredExtensions as $extension) { if (!extension_loaded($extension)) { $report['status'] = false; $report['errors'][] = "الامتداد المطلوب '{$extension}' غير مفعل في PHP."; } } foreach ($this->requiredDirectories as $directory) { $path = base_path($directory); if (!is_writable($path)) { $report['status'] = false; $report['errors'][] = "المجلد '{$directory}' لا يمتلك صلاحيات الكتابة المطلوبة."; } } if (!file_exists(base_path('.env'))) { $report['status'] = false; $report['errors'][] = "ملف الإعدادات '.env' مفقود في المجلد الجذري."; } return $report; } public function runOrFail(): void { $report = $this->check(); if (!$report['status']) { throw new Exception("فشل التحقق من البيئة: " . implode(' | ', $report['errors'])); } } }